  1	import { Bullseye, Spinner } from '@patternfly/react-core';
  2	import { SortByDirection, Table, Tbody } from '@patternfly/react-table';
  3	import * as _ from 'lodash';
  4	import * as React from 'react';
  5	
  6	import { Record } from '../../../api/ipfix';
  7	import { defaultNetflowMetrics, Stats } from '../../../api/loki';
  8	import { Config } from '../../../model/config';
  9	import { useNetflowContext } from '../../../model/netflow-context';
 10	import { Column, ColumnsId, ColumnSizeMap } from '../../../utils/columns';
 11	import { TimeRange } from '../../../utils/datetime';
 12	import { getStructuredHTTPError } from '../../../utils/errors';
 13	import { mergeFlowReporters } from '../../../utils/flows';
 14	import {
 15	  localStorageSortDirectionKey,
 16	  localStorageSortIdKey,
 17	  useLocalStorage
 18	} from '../../../utils/local-storage-hook';
 19	import { convertRemToPixels } from '../../../utils/panel';
 20	import { usePrevious } from '../../../utils/previous-hook';
 21	import { Result } from '../../../utils/result';
 22	import { Size } from '../../dropdowns/table-display-dropdown';
 23	import { Empty } from '../../messages/empty';
 24	import { NetflowTableHeader } from './netflow-table-header';
 25	import NetflowTableRow from './netflow-table-row';
 26	import './netflow-table.css';
 27	
 28	export type NetflowTableHandle = {
 29	  fetch: (
 30	    range: number | TimeRange,
 31	    histogramRange: TimeRange | undefined,
 32	    showHistogram: boolean,
 33	    showDuplicates: boolean
 34	  ) => Promise<Stats[]> | undefined;
 35	};
 36	
 37	export interface NetflowTableProps {
 38	  allowPktDrops: boolean;
 39	  flows: Record[];
 40	  selectedRecord?: Record;
 41	  columns: Column[];
 42	  setColumns: (v: Column[]) => void;
 43	  columnSizes: ColumnSizeMap;
 44	  setColumnSizes: (v: ColumnSizeMap) => void;
 45	  size: Size;
 46	  onSelect: (record?: Record) => void;
 47	  loading?: boolean;
 48	  resetDefaultFilters?: (c?: Config) => void;
 49	  clearFilters?: () => void;
 50	  isDark?: boolean;
 51	}
 52	
 53	// eslint-disable-next-line react/display-name
 54	export const NetflowTable = React.forwardRef<NetflowTableHandle, NetflowTableProps>((props, ref) => {
 55	  const { caps, fetchCallbacks } = useNetflowContext();
 56	
 57	  //default to 300 to allow content to be rendered in tests
 58	  const [containerHeight, setContainerHeight] = React.useState(300);
 59	  const previousContainerHeight = usePrevious(containerHeight);
 60	  const [scrollPosition, setScrollPosition] = React.useState(0);
 61	  const previousScrollPosition = usePrevious(scrollPosition);
 62	  const [lastRender, setLastRender] = React.useState<string>('');
 63	  // index of the currently active column
 64	  const [activeSortId, setActiveSortId] = useLocalStorage<ColumnsId>(localStorageSortIdKey, ColumnsId.endtime);
 65	  const previousActiveSortIndex = usePrevious(activeSortId);
 66	  // sort direction of the currently active column
 67	  const [activeSortDirection, setActiveSortDirection] = useLocalStorage<SortByDirection>(
 68	    localStorageSortDirectionKey,
 69	    SortByDirection.asc
 70	  );
 71	  const previousActiveSortDirection = usePrevious(activeSortDirection);
 72	  const firstRender = React.useRef(true);
 73	  const width = props.columns.reduce((prev, cur) => prev + cur.width, 0);
 74	
 75	  const fetch = React.useCallback(
 76	    (
 77	      range: number | TimeRange,
 78	      histogramRange: TimeRange | undefined,
 79	      showHistogram: boolean,
 80	      showDuplicates: boolean
 81	    ) => {
 82	      const fq = caps.flowQuery;
 83	      const { getRecords, getMetrics } = caps.fetchFunctions;
 84	      const { metricsRef, setFlows, setMetrics } = fetchCallbacks;
 85	
 86	      if (!showHistogram) {
 87	        setMetrics(defaultNetflowMetrics);
 88	      }
 89	
 90	      let currentMetrics = metricsRef.current;
 91	
 92	      // table query is based on histogram range if available
 93	      const tableQuery = { ...fq };
 94	      if (histogramRange) {
 95	        tableQuery.startTime = histogramRange.from.toString();
 96	        tableQuery.endTime = histogramRange.to.toString();
 97	      }
 98	      const promises: Promise<Stats>[] = [
 99	        getRecords(tableQuery).then(res => {
100	          const flows = showDuplicates ? res.records : mergeFlowReporters(res.records);
101	          setFlows(flows);
102	          return res.stats;
103	        })
104	      ];
105	      if (showHistogram) {
106	        promises.push(
107	          Result.fromPromise(getMetrics({ ...fq, function: 'count', aggregateBy: 'app', type: 'Flows' }, range)).then(
108	            res => {
109	              const totalFlowCount = res.map(m => m.metrics[0]).mapError(err => getStructuredHTTPError(err));
110	              currentMetrics = { ...currentMetrics, totalFlowCount };
111	              setMetrics(currentMetrics);
112	              return res.map(r => r.stats).or({ numQueries: 0, limitReached: false, dataSources: [] } as Stats);
113	            }
114	          )
115	        );
116	      } else {
117	        currentMetrics = { ...currentMetrics, totalRate: Result.empty() };
118	        setMetrics(currentMetrics);
119	      }
120	      return Promise.all(promises);
121	    },
122	    [caps.flowQuery, caps.fetchFunctions, fetchCallbacks]
123	  );
124	
125	  React.useImperativeHandle(ref, () => ({
126	    fetch
127	  }));
128	
129	  React.useEffect(() => {
130	    if (firstRender.current) {
131	      firstRender.current = firstRender.current && props.flows.length == 0;
132	      return;
133	    }
134	    setLastRender(String(Date.now()));
135	  }, [props.flows]);
136	
137	  /* remove rows from previous rendering that should not appear anymore in body
138	   * this fix a bug in PF TableComposable when refresh occurs after scroll
139	   * without rebuilding the entire table */
140	  React.useEffect(() => {
141	    const tbody = document.getElementById('table-body');
142	    if (tbody) {
143	      const children = Array.from(tbody.children);
144	      for (let i = 0; i < children.length; i++) {
145	        const child = children[i];
146	        const childLastRender = child.getAttribute('data-last-render');
147	        if (childLastRender !== lastRender) {
148	          child.remove();
149	        }
150	      }
151	    }
152	  }, [lastRender]);
153	
154	  //reset sort index & directions to default on columns update
155	  React.useEffect(() => {
156	    const found = props.columns.find(c => c.id === activeSortId);
157	    if (!found) {
158	      setActiveSortId(ColumnsId.endtime);
159	      setActiveSortDirection(SortByDirection.asc);
160	    }
161	    // eslint-disable-next-line react-hooks/exhaustive-deps
162	  }, [props.columns]);
163	
164	  //get row height from display size
165	  const getRowHeight = React.useCallback(() => {
166	    const doubleSizeColumnIds = props.columns.filter(c => c.isCommon).map(c => c.id);
167	    const containsDoubleLine = props.columns.find(c => doubleSizeColumnIds.includes(c.id)) !== undefined;
168	
169	    switch (props.size) {
170	      case 'l':
171	        return convertRemToPixels(containsDoubleLine ? 8 : 4.5);
172	      case 'm':
173	        return convertRemToPixels(containsDoubleLine ? 6 : 3.5);
174	      case 's':
175	      default:
176	        return convertRemToPixels(containsDoubleLine ? 4 : 2.5);
177	    }
178	    // eslint-disable-next-line react-hooks/exhaustive-deps
179	  }, [props.columns, props.size]);
180	
181	  //update table container height on window resize
182	  const handleResize = React.useCallback(() => {
183	    const container = document.getElementById('table-container');
184	    if (container) {
185	      setContainerHeight(container.clientHeight);
186	    }
187	  }, []);
188	
189	  const handleScroll = React.useCallback(() => {
190	    const rowHeight = getRowHeight();
191	    const container = document.getElementById('table-container');
192	    const header = container?.children[0]?.children[0]?.children[0];
193	    if (container && header) {
194	      const position = container.scrollTop - header.clientHeight;
195	      //updates only when position moved more than one row height
196	      if (scrollPosition < position - rowHeight || scrollPosition > position + rowHeight) {
197	        setScrollPosition(position);
198	      }
199	    }
200	  }, [getRowHeight, scrollPosition]);
201	
202	  React.useEffect(() => {
203	    handleScroll();
204	    handleResize();
205	    const container = document.getElementById('table-container');
206	    if (container && container.getAttribute('listener') !== 'true') {
207	      container.addEventListener('scroll', handleScroll);
208	    }
209	
210	    window.addEventListener('resize', handleResize);
211	    return () => {
212	      window.removeEventListener('resize', handleResize);
213	    };
214	  }, [handleResize, handleScroll, props.loading]);
215	
216	  // sort function
217	  const getSortedFlows = React.useCallback(() => {
218	    const found = activeSortId && props.columns.find(c => c.id === activeSortId);
219	    if (!found) {
220	      return props.flows;
221	    } else {
222	      return activeSortDirection === 'desc'
223	        ? props.flows.sort((a: Record, b: Record) => found.sort(a, b, found))
224	        : props.flows.sort((a: Record, b: Record) => found.sort(b, a, found));
225	    }
226	  }, [activeSortDirection, activeSortId, props.columns, props.flows]);
227	
228	  // sort handler
229	  const onSort = React.useCallback(
230	    (columnId: ColumnsId, direction: SortByDirection) => {
231	      setActiveSortId(columnId);
232	      setActiveSortDirection(direction);
233	    },
234	    [setActiveSortDirection, setActiveSortId]
235	  );
236	
237	  const getBody = React.useCallback(() => {
238	    const rowHeight = getRowHeight();
239	
240	    return getSortedFlows().map((f, i) => (
241	      <NetflowTableRow
242	        rowNumber={i}
243	        key={f.key}
244	        allowPktDrops={props.allowPktDrops}
245	        flow={f}
246	        lastRender={lastRender}
247	        columns={props.columns}
248	        size={props.size}
249	        selectedRecord={props.selectedRecord}
250	        onSelect={props.onSelect}
251	        highlight={
252	          previousContainerHeight === containerHeight &&
253	          previousScrollPosition === scrollPosition &&
254	          previousActiveSortDirection === activeSortDirection &&
255	          previousActiveSortIndex === activeSortId &&
256	          !firstRender.current
257	        }
258	        height={rowHeight}
259	        showContent={scrollPosition <= i * rowHeight && scrollPosition + containerHeight > i * rowHeight}
260	        tableWidth={width}
261	        isDark={props.isDark}
262	      />
263	    ));
264	  }, [
265	    props.allowPktDrops,
266	    lastRender,
267	    activeSortDirection,
268	    activeSortId,
269	    props.columns,
270	    containerHeight,
271	    getRowHeight,
272	    getSortedFlows,
273	    props.onSelect,
274	    previousActiveSortDirection,
275	    previousActiveSortIndex,
276	    previousContainerHeight,
277	    previousScrollPosition,
278	    scrollPosition,
279	    props.selectedRecord,
280	    props.size,
281	    width,
282	    props.isDark
283	  ]);
284	
285	  if (width === 0) {
286	    return null;
287	  } else if (_.isEmpty(props.flows)) {
288	    if (props.loading) {
289	      return (
290	        <Bullseye data-test="loading-contents">
291	          <Spinner size="xl" />
292	        </Bullseye>
293	      );
294	    } else {
295	      return (
296	        <Bullseye data-test="no-results-found">
297	          <Empty showDetails={true} resetDefaultFilters={props.resetDefaultFilters} clearFilters={props.clearFilters} />
298	        </Bullseye>
299	      );
300	    }
301	  }
302	
303	  return (
304	    <div id="table-container">
305	      <Table
306	        data-test="table-composable"
307	        data-test-cols-count={props.columns.length}
308	        data-test-rows-count={props.flows.length}
309	        aria-label="Netflow table"
310	        variant="compact"
311	        style={{ minWidth: `${width}em` }}
312	        isStickyHeader
313	      >
314	        <NetflowTableHeader
315	          data-test="table-header"
316	          onSort={onSort}
317	          sortDirection={activeSortDirection}
318	          sortId={activeSortId}
319	          columns={props.columns}
320	          setColumns={props.setColumns}
321	          columnSizes={props.columnSizes}
322	          setColumnSizes={props.setColumnSizes}
323	          tableWidth={width}
324	        />
325	        <Tbody id="table-body" data-test="table-body">
326	          {getBody()}
327	        </Tbody>
328	      </Table>
329	    </div>
330	  );
331	});
332	
333	export default NetflowTable;

