  1	import { SortByDirection, Th, Thead, Tr } from '@patternfly/react-table';
  2	import _ from 'lodash';
  3	import * as React from 'react';
  4	import {
  5	  Column,
  6	  ColumnGroup,
  7	  ColumnsId,
  8	  ColumnSizeMap,
  9	  getColumnGroups,
 10	  getFullColumnName,
 11	  getShortColumnName
 12	} from '../../../utils/columns';
 13	import './netflow-table-header.css';
 14	
 15	export type HeadersState = {
 16	  nestedHeaders: ColumnGroup[];
 17	  useNested: boolean;
 18	  headers: Column[];
 19	};
 20	
 21	export type ResizedElement = {
 22	  target: HTMLElement;
 23	  startClientX: number;
 24	  startClentWidth: number;
 25	};
 26	
 27	export interface NetflowTableHeaderProps {
 28	  onSort: (id: ColumnsId, direction: SortByDirection) => void;
 29	  sortId: ColumnsId;
 30	  sortDirection: SortByDirection;
 31	  columns: Column[];
 32	  setColumns: (v: Column[]) => void;
 33	  columnSizes: ColumnSizeMap;
 34	  setColumnSizes: (v: ColumnSizeMap) => void;
 35	  tableWidth: number;
 36	}
 37	
 38	export const NetflowTableHeader: React.FC<NetflowTableHeaderProps> = ({
 39	  onSort,
 40	  sortId,
 41	  sortDirection,
 42	  columns,
 43	  setColumns,
 44	  columnSizes,
 45	  setColumnSizes,
 46	  tableWidth
 47	}) => {
 48	  const resizedElement = React.useRef<ResizedElement>();
 49	  const draggedElement = React.useRef<HTMLElement>();
 50	
 51	  const [headersState, setHeadersState] = React.useState<HeadersState>({
 52	    nestedHeaders: [],
 53	    useNested: false,
 54	    headers: []
 55	  });
 56	
 57	  const mouseEvent = React.useCallback(
 58	    (e: MouseEvent) => {
 59	      const diffPx = e.clientX - resizedElement.current!.startClientX;
 60	      switch (e.type) {
 61	        case 'mousemove':
 62	          const minWidth = Number(resizedElement.current!.target.style.minWidth?.replace('px', '')) || 0;
 63	          if (Math.abs(minWidth - diffPx) > 10) {
 64	            const minWidth = `${resizedElement.current!.startClentWidth + diffPx}px`;
 65	            columnSizes[resizedElement.current!.target.id as ColumnsId] = minWidth;
 66	            resizedElement.current!.target.style.minWidth = minWidth;
 67	          }
 68	          break;
 69	        default:
 70	          document.getElementById('cursor-style')!.remove();
 71	          resizedElement.current!.target.classList.remove('resizing');
 72	          document.removeEventListener('mousemove', mouseEvent);
 73	          document.removeEventListener('mouseup', mouseEvent);
 74	          setColumnSizes(columnSizes);
 75	          break;
 76	      }
 77	    },
 78	    [columnSizes, setColumnSizes]
 79	  );
 80	
 81	  const onMouseDown = React.useCallback(
 82	    (e: React.MouseEvent<HTMLElement>) => {
 83	      const target = e.currentTarget;
 84	      if (target.classList.contains('column') && e.nativeEvent.offsetX > target.clientWidth - 15) {
 85	        target.classList.add('resizing');
 86	        const cursorStyle = document.createElement('style');
 87	        cursorStyle.innerHTML = '*{cursor: col-resize!important;}';
 88	        cursorStyle.id = 'cursor-style';
 89	        document.head.appendChild(cursorStyle);
 90	        resizedElement.current = { target, startClientX: e.clientX, startClentWidth: target.clientWidth };
 91	        document.addEventListener('mousemove', mouseEvent);
 92	        document.addEventListener('mouseup', mouseEvent);
 93	        e.preventDefault();
 94	      }
 95	    },
 96	    [mouseEvent]
 97	  );
 98	
 99	  const onDragStart = React.useCallback((e: React.DragEvent<HTMLElement>) => {
100	    const target = e.currentTarget;
101	    target.classList.add('dragged');
102	    draggedElement.current = target;
103	  }, []);
104	
105	  const clearDragEffects = () => {
106	    document.querySelectorAll('.netobserv-header').forEach(e => {
107	      if (e.classList.contains('dragged')) {
108	        e.classList.remove('dragged');
109	      }
110	
111	      if (e.classList.contains('dropzone')) {
112	        e.classList.remove('dropzone');
113	      }
114	    });
115	  };
116	
117	  const onDrop = React.useCallback(
118	    (e: React.DragEvent<HTMLElement>) => {
119	      if (!e.currentTarget || !draggedElement.current) {
120	        console.error('onDrop called while currentTarget or draggedElement ref missing');
121	        return;
122	      }
123	
124	      if (
125	        (e.currentTarget.classList.contains('nested') && draggedElement.current.classList.contains('nested')) ||
126	        (e.currentTarget.classList.contains('column') && draggedElement.current.classList.contains('column'))
127	      ) {
128	        const srcIndex = Number(draggedElement.current.getAttribute('data-index'));
129	        const srcColSpan = Number(draggedElement.current!.getAttribute('colSpan'));
130	        const dstIndex = Number(e.currentTarget.getAttribute('data-index'));
131	
132	        const result = [...columns];
133	        const removed = result.splice(srcIndex, srcColSpan);
134	        result.splice(dstIndex, 0, ...removed);
135	        setColumns(result);
136	      }
137	
138	      e.preventDefault();
139	    },
140	    [columns, setColumns]
141	  );
142	
143	  const getNestedTableHeader = React.useCallback(
144	    (nh: ColumnGroup) => {
145	      return (
146	        <Th
147	          className="netobserv-header nested"
148	          data-test={`nested-th-${nh.title || 'empty'}`}
149	          data-index={columns.indexOf(nh.columns[0])}
150	          key={`nested-${nh.title}-${headersState.nestedHeaders.indexOf(nh)}`}
151	          id={`nested-${headersState.nestedHeaders.indexOf(nh)}`}
152	          hasRightBorder={_.last(headersState.nestedHeaders) !== nh}
153	          colSpan={nh.columns.length}
154	          draggable
155	          onDragStart={onDragStart}
156	          onDragOver={e => {
157	            if (draggedElement.current?.classList.contains('nested')) {
158	              e.currentTarget.classList.add('dropzone');
159	            }
160	            e.preventDefault();
161	          }}
162	          onDragLeave={e => {
163	            e.currentTarget.classList.remove('dropzone');
164	            e.preventDefault();
165	          }}
166	          onDrop={onDrop}
167	          onDragEnd={clearDragEffects}
168	        >
169	          {nh.title}
170	        </Th>
171	      );
172	    },
173	    [columns, headersState.nestedHeaders, onDragStart, onDrop]
174	  );
175	
176	  const getTableHeader = React.useCallback(
177	    (c: Column) => {
178	      const showBorder =
179	        headersState.useNested && headersState.nestedHeaders.find(nh => _.last(nh.columns) === c) !== undefined;
180	      return (
181	        <Th
182	          className="netobserv-header column"
183	          data-test={`th-${c.id}`}
184	          data-index={columns.indexOf(c)}
185	          hasRightBorder={showBorder}
186	          key={c.id}
187	          id={c.id}
188	          sort={{
189	            sortBy: {
190	              index: columns.findIndex(c => c.id === sortId),
191	              direction: SortByDirection[sortDirection as SortByDirection]
192	            },
193	            onSort: (event, index, direction) => onSort(c.id, direction),
194	            columnIndex: columns.indexOf(c)
195	          }}
196	          colSpan={1}
197	          draggable
198	          onMouseDown={onMouseDown}
199	          onDragStart={onDragStart}
200	          onDragOver={e => {
201	            if (draggedElement.current?.classList.contains('column')) {
202	              e.currentTarget.classList.add('dropzone');
203	            }
204	            e.preventDefault();
205	          }}
206	          onDragLeave={e => {
207	            e.currentTarget.classList.remove('dropzone');
208	            e.preventDefault();
209	          }}
210	          onDrop={onDrop}
211	          onDragEnd={clearDragEffects}
212	          modifier="wrap"
213	          style={{ width: `${Math.floor((100 * c.width) / tableWidth)}%`, minWidth: columnSizes[c.id] }}
214	          info={
215	            [
216	              ColumnsId.starttime,
217	              ColumnsId.endtime,
218	              ColumnsId.collectiontime,
219	              ColumnsId.collectionlatency,
220	              ColumnsId.flowdirints,
221	              ColumnsId.dnslatency,
222	              ColumnsId.dnsresponsecode
223	            ].includes(c.id) && c.tooltip
224	              ? { tooltip: c.tooltip }
225	              : undefined
226	          }
227	        >
228	          {headersState.useNested ? getShortColumnName(c) : getFullColumnName(c)}
229	        </Th>
230	      );
231	    },
232	    [
233	      columnSizes,
234	      columns,
235	      headersState.nestedHeaders,
236	      headersState.useNested,
237	      onDragStart,
238	      onDrop,
239	      onMouseDown,
240	      onSort,
241	      sortDirection,
242	      sortId,
243	      tableWidth
244	    ]
245	  );
246	
247	  React.useEffect(() => {
248	    const nestedHeaders = getColumnGroups(columns);
249	    const useNested = nestedHeaders.find(nh => nh.columns.length > 1) !== undefined;
250	    const headers = useNested ? nestedHeaders.flatMap(nh => nh.columns) : columns;
251	    setHeadersState({ nestedHeaders, useNested, headers });
252	  }, [columns]);
253	
254	  return (
255	    <Thead className="bottom-shadow" data-test="thead" hasNestedHeader={headersState.useNested}>
256	      {headersState.useNested && <Tr>{headersState.nestedHeaders.map(nh => getNestedTableHeader(nh))}</Tr>}
257	      <Tr data-test="thead-tr">{headersState.headers.map(c => getTableHeader(c))}</Tr>
258	    </Thead>
259	  );
260	};

